import{c as t,Q as a,j as n,m as o}from"./chunks/framework.rlpw0eGz.js";const g=JSON.parse('{"title":"WeChat Channel Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"channels/weixin.md","filePath":"channels/weixin.md","lastUpdated":1774787421000}'),i={name:"channels/weixin.md"};function r(s,e,l,h,d,c){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="wechat-channel-configuration" tabindex="-1">WeChat Channel Configuration <a class="header-anchor" href="#wechat-channel-configuration" aria-label="Permalink to &quot;WeChat Channel Configuration&quot;">​</a></h1><p>Connecting your Memoh Bot to WeChat allows it to interact with users directly via WeChat personal messaging. Setup is simple — just scan a QR code.</p><h2 id="step-1-add-wechat-channel-in-memoh" tabindex="-1">Step 1: Add WeChat Channel in Memoh <a class="header-anchor" href="#step-1-add-wechat-channel-in-memoh" aria-label="Permalink to &quot;Step 1: Add WeChat Channel in Memoh&quot;">​</a></h2><ol><li>Go to your Bot&#39;s <strong>Platforms</strong> tab in the Memoh Web UI.</li><li>Click <strong>Add Channel</strong> and select <strong>WeChat</strong>.</li></ol><h2 id="step-2-scan-the-qr-code" tabindex="-1">Step 2: Scan the QR Code <a class="header-anchor" href="#step-2-scan-the-qr-code" aria-label="Permalink to &quot;Step 2: Scan the QR Code&quot;">​</a></h2><ol><li>Click <strong>Start QR Login</strong>. Memoh will fetch a QR code from the WeChat platform.</li><li>Open WeChat on your phone and scan the displayed QR code.</li><li>Confirm the login on your phone when prompted.</li><li>Once confirmed, Memoh automatically saves the credentials — no manual token or API key entry is needed.</li></ol><p>The QR code has a limited validity window. If it expires before you scan, click <strong>Start QR Login</strong> again to get a fresh one.</p><h2 id="step-3-start-chatting" tabindex="-1">Step 3: Start Chatting <a class="header-anchor" href="#step-3-start-chatting" aria-label="Permalink to &quot;Step 3: Start Chatting&quot;">​</a></h2><p>After the QR login succeeds, the channel is automatically enabled. Users can now send messages to the bot directly in WeChat.</p><h2 id="optional-settings" tabindex="-1">Optional Settings <a class="header-anchor" href="#optional-settings" aria-label="Permalink to &quot;Optional Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Enable Typing</strong></td><td>Show typing indicators while generating responses.</td></tr></tbody></table><h2 id="features-supported" tabindex="-1">Features Supported <a class="header-anchor" href="#features-supported" aria-label="Permalink to &quot;Features Supported&quot;">​</a></h2><ul><li><strong>Message Content</strong>: Full support for text messages.</li><li><strong>Direct Messages</strong>: Private conversations with individual users.</li><li><strong>Attachments</strong>: Support for images and media.</li><li><strong>Typing Indicators</strong>: Visual feedback while generating responses (when enabled).</li></ul>',13)])])}const u=t(i,[["render",r]]);export{g as __pageData,u as default};
